using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;

int n, m;
signed main(void)
{
	cin >> n >> m;
	int a[n+5][m+5],sum[n+5][m+5];
	FOR(i,0,n)
	{
		sum[i][0] = 0;	
	}
	FOR(i,0,m)
	{
		sum[0][i] = 0;	
	}
	FOR(i,1,n) 
	{
		FOR(j,1,m)
		{
			cin >> a[i][j];
			sum[i][j] = sum[i - 1][j] + sum[i][j - 1] - sum[i - 1][j - 1] + a[i][j];
		}		
	}
	if (n < m)
	{
		int f[n + 5][n + 5][m + 5];
		FOR(i,1,n)
		{
			FOR(j,i,n)
			{
				ROF(k,m,1)
				{
					if (m == k)
					{
						f[i][j][k] = sum[j][m] - sum[i - 1][m] - sum[j][m - 1] + sum[i - 1][m - 1];
					}
					else
					{
						f[i][j][k] = sum[j][k] - sum[i - 1][k] - sum[j][k - 1] + sum[i - 1][k - 1];
						if (f[i][j][k + 1] >= 0)
						{
							f[i][j][k] += f[i][j][k + 1];
						}
					}
				}
			}			
		}
		int q;
		cin >> q;
		while (q--)
		{
			int x, y;
			int ans = -llinf;
			cin >> x >> y;
			FOR(i,1,n-x+1)
				ans = max(ans, f[x][x + i - 1][y]);
			cout << ans << '\n';
		}
	}
	else
	{
		int f[m + 5][m + 5][n + 5];
		FOR(i,1,m)
		{
			FOR(j,i,m)
			{
				ROF(k,n,1)
				{
					if (n == k)
					{
						f[i][j][k] = sum[n][j] - sum[n][i - 1] - sum[n - 1][j] + sum[n - 1][i - 1];						
					}
					else
					{
						f[i][j][k] = sum[k][j] - sum[k][i - 1] - sum[k - 1][j] + sum[k - 1][i - 1];
						if (f[i][j][k + 1] >= 0)
						{
							f[i][j][k] += f[i][j][k + 1];
						}
					}
				}
			}
		}
		int q;
		cin >> q;
		wh(q--)
		{
			int x, y;
			int ans = -llinf;
			cin >> x >> y;
			FOR(i,1,m-y+1)
			{
				ans = max(ans, f[y][y + i - 1][x]);
			}
			cout << ans << '\n';
		}
	}
	return false;
}
